import{c as s,Q as t,j as i,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"灰度发布、分阶段发布与回滚策略","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/09-灰度发布分阶段发布与回滚策略.md","filePath":"mobileCommonLearning/09-灰度发布分阶段发布与回滚策略.md","lastUpdated":1780912084000}'),l={name:"mobileCommonLearning/09-灰度发布分阶段发布与回滚策略.md"};function n(p,a,h,d,r,o){return t(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="灰度发布、分阶段发布与回滚策略" tabindex="-1">灰度发布、分阶段发布与回滚策略 <a class="header-anchor" href="#灰度发布、分阶段发布与回滚策略" aria-label="Permalink to &quot;灰度发布、分阶段发布与回滚策略&quot;">​</a></h1><p>移动端发布不能像后端一样秒级回滚。包一旦到用户手机上,你就要和它长期相处。</p><p>一句话先记住:<strong>移动端灰度的目标不是省审核时间,而是在错误影响全量用户前发现并止损。</strong></p><hr><h2 id="一、为什么移动端回滚难" tabindex="-1">一、为什么移动端回滚难 <a class="header-anchor" href="#一、为什么移动端回滚难" aria-label="Permalink to &quot;一、为什么移动端回滚难&quot;">​</a></h2><p>后端:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>部署新版本 -&gt; 出问题 -&gt; 切回旧版本</span></span></code></pre></div><p>移动端:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户已经下载新包</span></span>
<span class="line"><span>商店审核有时间</span></span>
<span class="line"><span>用户不一定立刻更新</span></span>
<span class="line"><span>旧包和新包长期共存</span></span></code></pre></div><p>所以移动端更依赖:</p><ul><li>灰度</li><li>服务端开关</li><li>兼容协议</li><li>强制升级策略</li><li>事故预案</li></ul><hr><h2 id="二、灰度方式" tabindex="-1">二、灰度方式 <a class="header-anchor" href="#二、灰度方式" aria-label="Permalink to &quot;二、灰度方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td>商店分阶段发布</td><td>按比例推送给用户</td></tr><tr><td>渠道灰度</td><td>先发内部渠道 / 小渠道</td></tr><tr><td>服务端 feature flag</td><td>新功能按用户 / 版本打开</td></tr><tr><td>账号白名单</td><td>只给内部账号开放</td></tr><tr><td>地域 / 设备灰度</td><td>按地区、机型、系统版本控制</td></tr></tbody></table><p>移动端最稳的是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先发测试渠道 -&gt; 小比例商店灰度 -&gt; feature flag 控制功能 -&gt; 逐步放量</span></span></code></pre></div><hr><h2 id="三、app-store-分阶段发布" tabindex="-1">三、App Store 分阶段发布 <a class="header-anchor" href="#三、app-store-分阶段发布" aria-label="Permalink to &quot;三、App Store 分阶段发布&quot;">​</a></h2><p>App Store 支持分阶段发布。你可以让新版本逐步覆盖用户。</p><p>注意:</p><ul><li>Apple 审核通过不代表应该立刻全量。</li><li>分阶段发布期间仍要看 crash 和核心业务指标。</li><li>如果出问题,可以暂停发布,但已更新用户不会自动降级。</li></ul><hr><h2 id="四、google-play-分阶段发布" tabindex="-1">四、Google Play 分阶段发布 <a class="header-anchor" href="#四、google-play-分阶段发布" aria-label="Permalink to &quot;四、Google Play 分阶段发布&quot;">​</a></h2><p>Google Play staged rollout 可以按比例发布:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1% -&gt; 5% -&gt; 10% -&gt; 25% -&gt; 50% -&gt; 100%</span></span></code></pre></div><p>放量前看:</p><ul><li>crash-free users</li><li>ANR rate</li><li>install failure</li><li>rating / reviews</li><li>关键业务成功率</li></ul><p>不要只看&quot;没有人反馈&quot;。</p><hr><h2 id="五、服务端开关" tabindex="-1">五、服务端开关 <a class="header-anchor" href="#五、服务端开关" aria-label="Permalink to &quot;五、服务端开关&quot;">​</a></h2><p>移动端必须有服务端开关:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FeatureFlags</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  newCheckout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  enableLiveChat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  forceUpgradeMinVersion</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><p>用途:</p><ul><li>关闭新功能</li><li>禁用高风险入口</li><li>控制灰度用户</li><li>强制升级</li><li>降级到旧协议</li></ul><p>不要把所有开关写死在 App 包里。</p><hr><h2 id="六、协议兼容" tabindex="-1">六、协议兼容 <a class="header-anchor" href="#六、协议兼容" aria-label="Permalink to &quot;六、协议兼容&quot;">​</a></h2><p>移动端多版本共存,后端不能只支持最新包。</p><p>规则:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新增字段:可以</span></span>
<span class="line"><span>删除字段:危险</span></span>
<span class="line"><span>改字段类型:危险</span></span>
<span class="line"><span>改枚举含义:危险</span></span>
<span class="line"><span>强制新参数:危险</span></span></code></pre></div><p>后端接口至少要兼容当前线上主力版本。</p><p>推荐:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App 发版前确认最低支持版本</span></span>
<span class="line"><span>接口变更做向后兼容</span></span>
<span class="line"><span>必要时按 appVersion 分支</span></span>
<span class="line"><span>废弃接口先监控调用量</span></span></code></pre></div><hr><h2 id="七、回滚手段" tabindex="-1">七、回滚手段 <a class="header-anchor" href="#七、回滚手段" aria-label="Permalink to &quot;七、回滚手段&quot;">​</a></h2><p>移动端回滚分几类:</p><table tabindex="0"><thead><tr><th>手段</th><th>适用</th></tr></thead><tbody><tr><td>暂停灰度</td><td>新包还没全量</td></tr><tr><td>下架版本</td><td>严重问题,阻止继续下载</td></tr><tr><td>服务端关闭功能</td><td>新功能出问题</td></tr><tr><td>强制升级</td><td>旧版本有安全 / 协议问题</td></tr><tr><td>后端兼容旧协议</td><td>新包 / 旧包共存</td></tr><tr><td>发修复包</td><td>最终解决</td></tr></tbody></table><p>不要把&quot;发修复包&quot;当唯一手段。审核和用户更新都需要时间。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>新接口只支持新版 App,旧版用户全挂。</li><li>全量后才发现某机型启动崩溃。</li><li>灰度期间只看 crash,没看支付成功率。</li><li>feature flag 默认打开,新包一上线全用户可见。</li><li>下架后官网 APK 仍然能下载坏版本。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] 是否有分阶段发布计划</li><li>[ ] 是否有 feature flag</li><li>[ ] 后端是否兼容旧版本</li><li>[ ] 是否定义最低支持版本</li><li>[ ] 是否能暂停新功能</li><li>[ ] 是否有强制升级能力</li><li>[ ] 是否监控 crash / ANR / 核心业务指标</li><li>[ ] 官网和渠道是否能同步下架坏包</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>灰度发现问题</span></span>
<span class="line"><span>开关控制影响面</span></span>
<span class="line"><span>协议兼容保护旧版本</span></span>
<span class="line"><span>暂停和下架阻止继续扩散</span></span>
<span class="line"><span>修复包解决根因</span></span></code></pre></div><p>下一篇 10 讲多环境、多 flavor 与渠道包。</p>`,58)])])}const u=s(l,[["render",n]]);export{g as __pageData,u as default};
